import React, { useEffect, useState } from 'react';
import api from '../services/api';

export default function Billing(){
  const [bills, setBills] = useState([]);

  async function load(){
    const res = await api.get('/billing');
    setBills(res.data);
  }
  useEffect(()=>{load()},[]);

  async function handlePay(id){
    await api.post(`/payment/simulate/${id}`);
    load();
  }

  return (
    <div>
      <h2>Billing</h2>
      <table className="table">
        <thead><tr><th>ID</th><th>Patient</th><th>Service</th><th>Amount</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>
          {bills.map(b=> (
            <tr key={b.id}>
              <td>{b.id}</td>
              <td>{b.patient?.name || b.patientId}</td>
              <td>{b.serviceType}</td>
              <td>{b.amount}</td>
              <td>{b.paymentStatus}</td>
              <td>
                {b.paymentStatus !== 'Paid' && <button className="btn" onClick={()=>handlePay(b.id)}>Pay Now</button>}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
